/* ── CURSOR ── */
function Cursor({ mouse }) {
  const [trail, setTrail] = useState({ x: 0, y: 0 });
  useEffect(() => {
    const id = requestAnimationFrame(() =>
      setTrail((p) => ({
        x: p.x + (mouse.x - p.x) * 0.1,
        y: p.y + (mouse.y - p.y) * 0.1,
      })),
    );
    return () => cancelAnimationFrame(id);
  });
  return (
    <>
      <div
        style={{
          position: "fixed",
          pointerEvents: "none",
          zIndex: 9999,
          left: mouse.x - 5,
          top: mouse.y - 5,
          width: 10,
          height: 10,
          borderRadius: "50%",
          background: "rgba(107,154,107,0.8)",
          mixBlendMode: "multiply",
        }}
      />
      <div
        style={{
          position: "fixed",
          pointerEvents: "none",
          zIndex: 9998,
          left: trail.x - 18,
          top: trail.y - 18,
          width: 36,
          height: 36,
          borderRadius: "50%",
          border: "1.5px solid rgba(107,154,107,0.4)",
        }}
      />
    </>
  );
}

